export class PartialResponseError extends Error{partialContent;constructor(r,t){super(r),this.name="PartialResponseError",this.partialContent=t}}export class ContextWindowExceededError extends Error{estimatedInputTokens;contextWindow;reservedOutput;constructor(r,t,s,o){super(r),this.name="ContextWindowExceededError",this.estimatedInputTokens=t,this.contextWindow=s,this.reservedOutput=o}}export class ModelServiceMismatchError extends Error{service;model;constructor(r,t){super(`Model "${t}" does not belong to service "${r}"`),this.name="ModelServiceMismatchError",this.service=r,this.model=t}}export class LLMRetryExhaustedError extends Error{lastError;attempts;constructor(r,t,s){super(r),this.name="LLMRetryExhaustedError",this.lastError=t,this.attempts=s}}export class LLMTimeoutError extends Error{timeoutMs;constructor(r,t){super(r),this.name="LLMTimeoutError",this.timeoutMs=t}}
